			TS:     in.Now,
			TSRaw:  in.Now.UTC().Format(time.RFC3339),
			URL:    in.URL,
			NewSHA: in.ResolvedSHA,
			OldSHA: in.ManifestTrustedSHA,
		}
		return d, nil
	}

