16	
17	// PendingStore owns the pending.jsonl queue described in
18	// docs/spec/trust-store-v1.md. Unlike Store, pending has no history — it
19	// is a queue: Append enqueues, List/Latest inspect, Clear removes.
20	//
21	// Pending entries arise from sync observing a known URL with a new SHA
22	// in a non-interactive path (or an interactive path where we've chosen not
23	// to prompt mid-sync, per plan decision #9). The user reviews via
24	// `aienvs trust pending` and promotes via `aienvs trust promote`.
25	type PendingStore struct {
26		path string
27		mu   sync.Mutex
28	}
29	
30	// NewPendingStore returns a PendingStore rooted at path.
31	func NewPendingStore(path string) *PendingStore {
32		return &PendingStore{path: path}
33	}
34	
35	// Path returns the absolute path to pending.jsonl.
36	func (p *PendingStore) Path() string {
37		return p.path
38	}
39	
40	// Append enqueues e. If the most-recent entry for e.URL already has the
41	// same NewSHA, the append is a no-op (spec rule: idempotent for the
42	// latest pair — keeps repeated syncs of the same manifest from ballooning
43	// the queue).
44	func (p *PendingStore) Append(e PendingEntry) error {
45		if err := validatePendingEntry(e); err != nil {
46			return err
47		}
48	
49		p.mu.Lock()
50		defer p.mu.Unlock()
51	
52		latest, err := p.latestLocked()
53		if err != nil {
54			return err
55		}
56		if prev, ok := latest[e.URL]; ok && prev.NewSHA == e.NewSHA {
57			return nil
58		}
59	
60		if err := os.MkdirAll(filepath.Dir(p.path), 0o700); err != nil {
61			return fmt.Errorf("trust: mkdir pending dir: %w", err)
62		}
63	
64		buf, err := marshalPendingEntry(e)
65		if err != nil {
66			return err
67		}
68	
69		f, err := os.OpenFile(p.path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o600)
70		if err != nil {
71			return fmt.Errorf("trust: open pending for append: %w", err)
72		}
73		defer func() { _ = f.Close() }()
74	
75		if _, err := f.Write(buf); err != nil {
76			return fmt.Errorf("trust: append pending: %w", err)
77		}
78		return nil
79	}
80	
81	// List returns every pending entry in arrival order.
82	func (p *PendingStore) List() ([]PendingEntry, error) {
83		f, err := os.Open(p.path)
84		if err != nil {
85			if errors.Is(err, os.ErrNotExist) {
86				return nil, nil
87			}
88			return nil, fmt.Errorf("trust: open pending: %w", err)
89		}
90		defer func() { _ = f.Close() }()
91	
92		return parsePendingLines(f, p.path)
93	}
94	
95	// Latest returns the latest pending entry per URL, keyed by URL.
96	func (p *PendingStore) Latest() (map[string]PendingEntry, error) {
97		entries, err := p.List()
98		if err != nil {
99			return nil, err
100		}
101		return foldPendingLatest(entries), nil
102	}
103	
104	// Clear removes every pending entry for url.
105	func (p *PendingStore) Clear(url string) error {
106		return p.rewrite(func(e PendingEntry) bool { return e.URL != url })
107	}
108	
109	// ClearAll empties the pending queue.
110	func (p *PendingStore) ClearAll() error {
111		p.mu.Lock()
112		defer p.mu.Unlock()
113		if err := os.Remove(p.path); err != nil && !errors.Is(err, os.ErrNotExist) {
114			return fmt.Errorf("trust: clear pending: %w", err)
115		}
116		return nil
117	}
118	
119	// --- internals ---
120	
121	// latestLocked is the fold without re-acquiring the mutex. Caller must
122	// hold p.mu.
123	func (p *PendingStore) latestLocked() (map[string]PendingEntry, error) {
124		f, err := os.Open(p.path)
125		if err != nil {
126			if errors.Is(err, os.ErrNotExist) {
127				return map[string]PendingEntry{}, nil
128			}
129			return nil, fmt.Errorf("trust: open pending: %w", err)
130		}
131		defer func() { _ = f.Close() }()
132	
133		entries, err := parsePendingLines(f, p.path)
134		if err != nil {
135			return nil, err
136		}
137		return foldPendingLatest(entries), nil
138	}
139	
140	// rewrite filters pending entries through keep and rewrites the file.
141	// Advisory-locked via gofrs/flock; on absent file, returns nil.
142	func (p *PendingStore) rewrite(keep func(PendingEntry) bool) error {
143		p.mu.Lock()
144		defer p.mu.Unlock()
145	
146		entries, err := p.List()
147		if err != nil {
148			return err
149		}
150		if len(entries) == 0 {
151			return nil
152		}
153	
154		lockPath := p.path + ".lock"
155		lk := flock.New(lockPath)
156		ctx, cancel := context.WithTimeout(context.Background(), compactLockTimeout)
157		defer cancel()
158		locked, err := lk.TryLockContext(ctx, 50*time.Millisecond)
159		if err != nil {
160			return fmt.Errorf("trust: acquire pending lock: %w", err)
161		}
162		if !locked {
163			return ErrLocked
164		}
165		defer func() { _ = lk.Unlock() }()
166	
167		dir := filepath.Dir(p.path)
168		tmp, err := os.CreateTemp(dir, "pending-*.jsonl.tmp")
169		if err != nil {
170			return fmt.Errorf("trust: create pending tmp: %w", err)
171		}
172		tmpPath := tmp.Name()
173		removeTmp := true
174		defer func() {
175			if removeTmp {
176				_ = os.Remove(tmpPath)
177			}
178		}()
179	
180		w := bufio.NewWriter(tmp)
181		kept := 0
182		for _, e := range entries {
183			if !keep(e) {
184				continue
185			}
186			buf, err := marshalPendingEntry(e)
187			if err != nil {
188				_ = tmp.Close()
189				return err
190			}
191			if _, err := w.Write(buf); err != nil {
192				_ = tmp.Close()
193				return fmt.Errorf("trust: write pending tmp: %w", err)
194			}
195			kept++
196		}
197		if err := w.Flush(); err != nil {
198			_ = tmp.Close()
199			return fmt.Errorf("trust: flush pending tmp: %w", err)
200		}
201		if err := tmp.Chmod(0o600); err != nil {
202			_ = tmp.Close()
203			return fmt.Errorf("trust: chmod pending tmp: %w", err)
204		}
205		if err := tmp.Close(); err != nil {
206			return fmt.Errorf("trust: close pending tmp: %w", err)
207		}
208	
209		if kept == 0 {
210			// No survivors — remove the original rather than leaving an empty file.
211			if err := os.Remove(p.path); err != nil && !errors.Is(err, os.ErrNotExist) {
212				return fmt.Errorf("trust: remove empty pending: %w", err)
213			}
214			return nil
215		}
216	
217		if err := os.Rename(tmpPath, p.path); err != nil {
218			return fmt.Errorf("trust: rename pending tmp: %w", err)
219		}
220		removeTmp = false
221		return nil
222	}
223	
224	// validatePendingEntry checks structural invariants.
225	func validatePendingEntry(e PendingEntry) error {
226		if e.URL == "" {
227			return errors.New("trust: pending: url is required")
