1	// Package cli holds cobra command factories for the aienvs CLI. Unit 6
2	// introduces the first subcommand tree (`aienvs trust`); Unit 16 will wire
3	// the full root command + fang styling.
4	package cli
5	
6	import (
7		"cmp"
8		"context"
9		"encoding/json"
10		"errors"
11		"fmt"
12		"io"
13		"os"
14		"os/exec"
15		"os/user"
16		"path/filepath"
17		"slices"
18		"time"
19	
20		"github.com/adrg/xdg"
21		"github.com/goccy/go-yaml"
22		"github.com/spf13/cobra"
23	
24		"github.com/aienvs/aienvs/internal/cache"
25		"github.com/aienvs/aienvs/internal/manifest"
26		"github.com/aienvs/aienvs/internal/trust"
27	)
28	
29	// yamlUnmarshal is a thin alias so we can keep the import list tidy and
30	// still swap out the unmarshaller from a single place if it changes.
31	var yamlUnmarshal = yaml.Unmarshal
32	
33	// TrustDeps is the injectable dependency bundle for the trust command
34	// tree. Production code calls NewTrustCommand with a zero Deps; tests fill
35	// in the hooks they need to observe.
36	type TrustDeps struct {
37		// Store and Pending are the persistence layers. When nil, command
38		// factories resolve them from xdg.DataHome / xdg.StateHome on first use.
39		Store   *trust.Store
40		Pending *trust.PendingStore
41	
42		// ManifestPath overrides `.aienv.yaml` discovery. When empty the
43		// command falls back to `$PWD/.aienv.yaml`.
44		ManifestPath string
45	
46		// Prompter is used for interactive subcommands (add, revoke, reset).
47		// When nil the factory constructs one from In/Out.
48		Prompter *trust.Prompter
49	
50		// In, Out, Err override os.Stdin, os.Stdout, os.Stderr for tests.
51		In  io.Reader
52		Out io.Writer
53		Err io.Writer
54	
55		// Now returns the reference time. Nil means time.Now.
56		Now func() time.Time
57	
58		// Actor and Hostname are recorded on every LogEntry append.
59		Actor    string
60		Hostname string
61	}
62	
63	// NewTrustCommand returns the `aienvs trust` cobra subtree. The caller
64	// (Unit 16) adds it to the root command.
65	func NewTrustCommand(deps TrustDeps) *cobra.Command {
66		cmd := &cobra.Command{
67			Use:   "trust",
68			Short: "Manage the two-tier trust store",
69			Long: "Manage the committed project pin (trusted_sha in .aienv.yaml) " +
70				"and the per-user trust history (trust.jsonl).",
71			SilenceUsage:  true,
72			SilenceErrors: true,
73		}
74	
75		cmd.AddCommand(
76			newTrustStatusCmd(deps),
77			newTrustPendingCmd(deps),
78			newTrustDiffCmd(deps),
79			newTrustPromoteCmd(deps),
80			newTrustPinCmd(deps),
81			newTrustVerifyCmd(deps),
