13	// DecodeOptions configures the decoder.
14	type DecodeOptions struct {
15		// KnownTargets, when non-nil, gates frontmatter `targets:` values: any
16		// entry not in the set is rejected with ErrUnknownTarget. When nil,
17		// the decoder accepts any string in `targets:` (useful for tests and
18		// for the v1 case where the adapter registry isn't wired yet).
19		KnownTargets map[string]struct{}
20	}
21	
22	// rootAgentsMDOverlay maps root-level overlay filenames to their target
23	// adapter scope. AGENTS.md itself is unscoped (empty target slice).
24	var rootAgentsMDOverlay = map[string]string{
25		"CLAUDE.md": "claude",
26		"GEMINI.md": "gemini",
27	}
28	
29	// Decode walks the canonical-repo tree at commitSHA and returns the IR
30	// produced from it. See docs/spec/ir-v1.md for the contract.
31	//
32	// The decoder is deterministic: same commit SHA → byte-identical IR
33	// (modulo Go map iteration in user-visible fields, which we explicitly
34	// sort).
35	func Decode(repo *git.Repository, commitSHA string, opts DecodeOptions) ([]Node, []Warning, error) {
36		entries, err := repo.ReadTree(commitSHA)
37		if err != nil {
38			return nil, nil, fmt.Errorf("ir: read tree: %w", err)
39		}
40	
41		var (
42			nodes    []Node
43			warnings []Warning
44			// Track which skill directories we've seen and whether each has a
45			// SKILL.md, so we can emit ErrSkillMissingSKILL for orphan dirs.
46			skillDirs   = map[string]bool{} // dir -> hasSKILL
47			hasAgentsMD = false
48			seenIDs     = map[Kind]map[string]string{} // kind -> id -> first path
49		)
50	
51		markSeen := func(k Kind, id, path string) error {
52			if _, ok := seenIDs[k]; !ok {
53				seenIDs[k] = map[string]string{}
54			}
55			if prev, dup := seenIDs[k][id]; dup {
56				return fmt.Errorf("%w: kind=%s id=%s (first at %q, again at %q)",
57					ErrDuplicateID, k, id, prev, path)
58			}
59			seenIDs[k][id] = path
60			return nil
61		}
62	
63		for _, e := range entries {
64			// Skip directory entries — TreeEntry covers regular files; sub-
65			// directories surface as their own entries with file-shaped paths.
66			if isDir(e.Mode) {
67				continue
68			}
69	
70			p := e.Path
71			switch {
72			case p == "AGENTS.md":
73				node, err := buildAgentsMD(repo, commitSHA, e, "" /* no overlay scope */)
74				if err != nil {
75					return nil, nil, err
76				}
77				if err := markSeen(KindAgentsMD, node.ID, p); err != nil {
78					return nil, nil, err
79				}
80				nodes = append(nodes, node)
81				hasAgentsMD = true
82	
83			case isOverlayPath(p):
84				node, err := buildAgentsMD(repo, commitSHA, e, rootAgentsMDOverlay[p])
85				if err != nil {
86					return nil, nil, err
87				}
88				if err := markSeen(KindAgentsMD, node.ID, p); err != nil {
89					return nil, nil, err
90				}
91				nodes = append(nodes, node)
92				// An overlay (CLAUDE.md / GEMINI.md) counts as an
93				// agents-md file for the purposes of WarnAgentsMDMissing:
94				// the warning fires only when neither canonical nor any
95				// overlay exists.
96				hasAgentsMD = true
97	
98			case strings.HasPrefix(p, "rules/"):
99				node, err := buildSimpleNode(repo, commitSHA, e, KindRule, "rules/", ".md")
100				if err != nil {
101					return nil, nil, err
102				}
103				if err := markSeen(KindRule, node.ID, p); err != nil {
104					return nil, nil, err
105				}
106				nodes = append(nodes, node)
107	
108			case strings.HasPrefix(p, "skills/"):
109				// Path shape: skills/<id>/SKILL.md or skills/<id>/<asset>.
110				// Bare skills/<file> (no <id>/ subdir) is an error.
111				rel := strings.TrimPrefix(p, "skills/")
112				parts := strings.SplitN(rel, "/", 2)
113				if len(parts) < 2 {
114					return nil, nil, fmt.Errorf("%w: stray file under skills/: %q",
115						ErrUnrecognizedFile, p)
116				}
117				id := parts[0]
118				leaf := parts[1]
119				dir := "skills/" + id
120				// Ensure the directory is seen at least once.
121				if _, ok := skillDirs[dir]; !ok {
122					skillDirs[dir] = false
123				}
124				if leaf == "SKILL.md" {
125					if !IsValidID(id) {
126						return nil, nil, fmt.Errorf("%w: skill id %q (from %q)", ErrInvalidID, id, p)
127					}
128					node, err := buildSkillNode(repo, commitSHA, e, id)
129					if err != nil {
130						return nil, nil, err
131					}
132					if err := markSeen(KindSkill, node.ID, p); err != nil {
133						return nil, nil, err
134					}
135					nodes = append(nodes, node)
136					skillDirs[dir] = true
137				}
138				// Non-SKILL.md files inside skills/<id>/ are assets, surfaced
139				// via SkillsByID. They do not become Nodes themselves.
140	
141			case strings.HasPrefix(p, "commands/"):
142				node, err := buildSimpleNode(repo, commitSHA, e, KindCommand, "commands/", ".md")
143				if err != nil {
144					return nil, nil, err
145				}
146				if err := markSeen(KindCommand, node.ID, p); err != nil {
147					return nil, nil, err
148				}
149				nodes = append(nodes, node)
150	
151			case strings.HasPrefix(p, "mcp/"):
152				node, err := buildSimpleNode(repo, commitSHA, e, KindMCPServerEntry, "mcp/", ".json")
153				if err != nil {
154					return nil, nil, err
155				}
156				if err := markSeen(KindMCPServerEntry, node.ID, p); err != nil {
157					return nil, nil, err
158				}
159				nodes = append(nodes, node)
160	
161			case strings.HasPrefix(p, "plugins/"):
162				node, err := buildSimpleNode(repo, commitSHA, e, KindPluginReference, "plugins/", ".toml")
163				if err != nil {
164					return nil, nil, err
165				}
166				if err := markSeen(KindPluginReference, node.ID, p); err != nil {
167					return nil, nil, err
168				}
169				nodes = append(nodes, node)
170	
171			default:
172				// Files outside IR-owned directories are ignored. README,
173				// LICENSE, etc. all live here harmlessly.
174				continue
175			}
176		}
177	
178		// Validate frontmatter targets against the registry, if provided.
179		for _, n := range nodes {
180			if err := validateTargets(n.Targets, opts.KnownTargets); err != nil {
181				return nil, nil, fmt.Errorf("%w (node %q at %q)", err, n.ID, n.Provenance.Path)
182			}
183		}
184	
185		// Skill orphan-dir check: every dir under skills/ must have SKILL.md.
186		// Iterate over sorted keys so that, when multiple skill dirs are
187		// orphaned, the error names the lexicographically-first dir
188		// deterministically — Go's randomized map iteration would otherwise
189		// pick a different one across runs.
190		orphanDirs := make([]string, 0, len(skillDirs))
191		for dir := range skillDirs {
192			orphanDirs = append(orphanDirs, dir)
193		}
194		sort.Strings(orphanDirs)
195		for _, dir := range orphanDirs {
196			if !skillDirs[dir] {
197				return nil, nil, fmt.Errorf("%w: %s", ErrSkillMissingSKILL, dir)
198			}
199		}
200	
201		// AGENTS.md missing → warning (not error). Only emit if no
202		// agents-md file (canonical or overlay) was found at all and the
203		// repo has any other IR content; greenfield repos with nothing in
204		// them get the warning too — that's the spec's intent.
205		if !hasAgentsMD {
206			warnings = append(warnings, Warning{
207				Code:    WarnAgentsMDMissing,
208				Message: "AGENTS.md is not present in the canonical repo",
209			})
210		}
211	
212		sortNodes(nodes)
213		return nodes, warnings, nil
214	}
