18			{Path: "rules/no-pr-on-friday.md", Content: "Don't ship on Friday.\n"},
19			{Path: "skills/review-guide/SKILL.md", Content: "---\nrequired: true\n---\nReview guide body.\n"},
20			{Path: "commands/ship-it.md", Content: "Ship the diff.\n"},
21			{Path: "mcp/linear.json", Content: `{"command":"linear-server"}`},
22			{Path: "plugins/ce.toml", Content: "name = \"ce\"\nversion = \"1.2.3\"\n"},
23		})
